    EmailIcon,
    FacebookIcon,
    InstapaperIcon,
    LineIcon,
    LinkedinIcon,
    LivejournalIcon,
    MailruIcon,
    OKIcon,
    PinterestIcon,
    PocketIcon,
    RedditIcon,
    TelegramIcon,
    TumblrIcon,
    TwitterIcon,
    ViberIcon,
    VKIcon,
    WeiboIcon,
    WhatsappIcon,
    WorkplaceIcon,
  } from "react-share";

class App extends Component {

    constructor(props) {
        super(props)
        this.state = {
            items : [],
            currentItem : {
                text : '' ,
                key : ''
        }
    }
}

    render() {

        const style = {
            margintop: '100px',
            marginleft: '300px'
        }



        return (   
            <div className = "App">   
          <header>

              <form id = "ToDo-Form"  >

                  {/* <img style={{height:'200px' ,marginRight:'60px' }  } src= {X} alt="Hello" /> */}
                  <img className="Img" src= {X} alt="Hello" />
                  <br/>
                  <br/>

                  {/* <input type="text" placeholder="Enter text" 
                //   value = {this.state.currentItem.text} 
                //   onChange={this.handleInput} 
                /> */}
                  <button >Add Item</button>
                  <br/>
                  <TwitterIcon size={42} round={true} />
                  <br/>
                  <FacebookIcon size={42} round={true} />
                  <br/>
                  <WhatsappIcon size={42} round={true} />

              </form>

          </header>

          <div className="App2" >

          </div>

          </div> 
        );
    }
}

export default App
